// Cruce determinístico horarios vs reservas

// Lee datos del trigger y de los dos nodos Airtable previos



const trigger = $('When Executed by Another Workflow').first().json;

const fecha = (trigger.fecha || '').toString().trim();

const diaSemana = (trigger.dia_semana || '').toString().trim();



if (!fecha || !/^\d{4}-\d{2}-\d{2}$/.test(fecha)) {

  return [{ json: {

    error: 'FECHA_INVALIDA',

    message: 'El parámetro fecha debe estar en formato YYYY-MM-DD. Ejemplo: 2026-04-20.'

  } }];

}



const diasValidos = ['Lunes','Martes','Miércoles','Jueves','Viernes','Sábado','Domingo'];

if (!diasValidos.includes(diaSemana)) {

  return [{ json: {

    error: 'DIA_INVALIDO',

    message: `dia_semana debe ser uno de: ${diasValidos.join(', ')}. Recibido: '${diaSemana}'`

  } }];

}



function normalizeTime(t) {

  if (!t) return '';

  const s = t.toString().trim();

  const ampm = s.match(/^(\d{1,2}):(\d{2})(?::\d{2})?\s*(AM|PM)$/i);

  if (ampm) {

    let h = parseInt(ampm[1], 10);

    const m = ampm[2];

    const period = ampm[3].toUpperCase();

    if (period === 'PM' && h !== 12) h += 12;

    if (period === 'AM' && h === 12) h = 0;

    return h.toString().padStart(2, '0') + ':' + m;

  }

  const parts = s.split(':');

  return parts.length >= 2 ? parts[0].padStart(2, '0') + ':' + parts[1].padStart(2, '0') : s;

}



// Normaliza un nombre de campo: minúsculas + sin tildes + sin espacios

function normKey(k) {

  return k.toString().toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '').replace(/[^a-z0-9]/g, '');

}



// Busca un campo tolerante a mayúsculas/tildes/espacios.

// Recibe el objeto fields y un array de nombres candidatos.

function getField(fields, candidates) {

  const map = {};

  for (const k of Object.keys(fields)) map[normKey(k)] = fields[k];

  for (const c of candidates) {

    const v = map[normKey(c)];

    if (v !== undefined) return v;

  }

  return undefined;

}



// Leer records de cada nodo Airtable por separado

const horariosItems = $('horarios').all();

const reservasItems = $('check_availability').all();



function pickFields(item) {

  // Airtable v2 devuelve fields top-level y también conserva .fields

  return (item && item.json && item.json.fields) ? item.json.fields : (item.json || {});

}



// Filtrar slots activos del día (multi-select 'Dias Activos')

const slotsDelDia = horariosItems

  .map(pickFields)

  .filter(r => {

    const dias = getField(r, ['Dias Activos', 'Días activos', 'dias_activos']) || [];

    if (Array.isArray(dias)) return dias.includes(diaSemana);

    return dias.toString().includes(diaSemana);

  });



if (slotsDelDia.length === 0) {

  return [{ json: {

    fecha,

    dia_semana: diaSemana,

    slots_disponibles: [],

    total_disponibles: 0,

    total_configurados: 0,

    message: `No hay slots configurados para ${diaSemana}. Verificar tabla Configuracion en Airtable.`

  } }];

}



// Estados que bloquean el slot (normalizados: lowercase + sin tildes)

const ESTADOS_BLOQUEANTES = ['pendiente', 'confirmada', 'senada'];

function normStr(s) {

  return (s || '').toString().toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '').trim();

}



// Cuántas canchas hay en total. Un slot sólo está ocupado si están TODAS
// tomadas a esa hora — no alcanza con que haya una reserva.
// CAMBIÁ este número al clonar para otro complejo (o pasalo desde Vibo).
const TOTAL_CANCHAS = Number($('When Executed by Another Workflow').first().json.TotalCanchas) || 2;

// Canchas DISTINTAS tomadas por hora. Set (no contador) para que una fila
// duplicada de la misma cancha no cuente doble.
const canchasPorHora = {};
for (const r of reservasItems.map(pickFields)) {
  const h = normalizeTime(getField(r, ['Hora inicio']));
  if (!h) continue;
  const cancha = normStr(getField(r, ['Cancha']));
  (canchasPorHora[h] = canchasPorHora[h] || new Set()).add(cancha);
}

const disponibles = slotsDelDia
  .filter((r) => {
    const h = normalizeTime(getField(r, ['Hora inicio']));
    const tomadas = canchasPorHora[h] ? canchasPorHora[h].size : 0;
    return tomadas < TOTAL_CANCHAS;
  })
  .map((r) => ({ hora_inicio: normalizeTime(getField(r, ['Hora inicio'])) }));

// slots_ocupados_horas: sólo las que están completas, para el reporte.
const ocupados = Object.keys(canchasPorHora)
  .filter((h) => canchasPorHora[h].size >= TOTAL_CANCHAS);



return [{ json: {

  fecha,

  dia_semana: diaSemana,

  slots_disponibles: disponibles,

  total_disponibles: disponibles.length,

  total_configurados: slotsDelDia.length,

  slots_ocupados_horas: ocupados

} }];

const data = $input.first().json;

// Solo filtrar si la fecha consultada es hoy
const hoy = new Date().toLocaleDateString('en-CA', {
  timeZone: 'America/Argentina/Buenos_Aires'
}); // Devuelve YYYY-MM-DD

if (data.fecha !== hoy) {
  const turnosLimpios = data.slots_disponibles.map(slot => slot.hora_inicio);

  return [{ json: { 
    fecha: data.fecha,
    turnos_disponibles: turnosLimpios
  }}]; 
}

// Es hoy -> obtener hora actual en Argentina
const ahoraStr = new Date().toLocaleTimeString('en-GB', {
  timeZone: 'America/Argentina/Buenos_Aires',
  hour: '2-digit',
  minute: '2-digit'
}); 

// Filtrar slots pasados y transformarlos a texto simple
const turnosLimpios = data.slots_disponibles
  .filter(slot => slot.hora_inicio > ahoraStr) 
  .map(slot => slot.hora_inicio);

return [{ json: { 
  fecha: data.fecha,
  turnos_disponibles: turnosLimpios
}}];
